class AiTutorRequest {
  const AiTutorRequest({
    required this.classId,
    required this.experimentId,
    required this.mode,
    required this.studentState,
  });

  final String classId;
  final String experimentId;
  final String mode;
  final Map<String, dynamic> studentState;

  Map<String, dynamic> toJson() {
    return {
      'classId': classId,
      'experimentId': experimentId,
      'mode': mode,
      'studentState': studentState,
    };
  }
}

class AiTutorResponse {
  const AiTutorResponse({
    required this.question,
    required this.feedback,
    required this.nextStep,
    required this.status,
  });

  final String question;
  final String feedback;
  final String nextStep;
  final String status;

  factory AiTutorResponse.fromJson(Map<String, dynamic> json) {
    return AiTutorResponse(
      question: (json['question'] ?? '').toString(),
      feedback: (json['feedback'] ?? '').toString(),
      nextStep: (json['nextStep'] ?? '').toString(),
      status: (json['status'] ?? '').toString(),
    );
  }
}

import 'dart:convert';

import 'package:http/http.dart' as http;

import 'ai_tutor_models.dart';

class AiTutorService {
  AiTutorService({http.Client? client, String? baseUrl})
    : _client = client ?? http.Client(),
      _baseUrl =
          baseUrl ??
          const String.fromEnvironment(
            'AI_BASE_URL',
            defaultValue: 'http://localhost:8000',
          );

  final http.Client _client;
  final String _baseUrl;

  Future<AiTutorResponse> getTutorResponse(AiTutorRequest request) async {
    final uri = Uri.parse('$_baseUrl/ai/tutor');
    final response = await _client.post(
      uri,
      headers: const {'Content-Type': 'application/json'},
      body: jsonEncode(request.toJson()),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('AI tutor request failed: ${response.statusCode}');
    }

    final payload = jsonDecode(response.body) as Map<String, dynamic>;
    return AiTutorResponse.fromJson(payload);
  }
}

