      );

      if (!mounted) return;
      setState(() {
        _aiQuestion = response.question;
        _aiFeedback = response.feedback;
        _aiNextStep = response.nextStep;
      });
    } catch (e) {
      if (!mounted) return;
      setState(() {
        _aiError =
            'Could not connect to AI backend. Check if backend is running on port 8000.';
