  @override
  void paint(Canvas canvas, Size size) {
    final cx = size.width * 0.5;
    final cy = size.height * 0.5;
    final mirrorLength = size.width * 0.35;

    final mirrorAngleRad = (mirrorAngleDegrees * math.pi) / 180;
    final halfAngle = mirrorAngleRad / 2;

    final mirror1EndX = cx + mirrorLength * math.sin(halfAngle);
    final mirror1EndY = cy - mirrorLength * math.cos(halfAngle);
    final mirror2EndX = cx + mirrorLength * math.sin(halfAngle);
    final mirror2EndY = cy + mirrorLength * math.cos(halfAngle);

    canvas.drawLine(
      Offset(cx, cy),
      Offset(mirror1EndX, mirror1EndY),
      Paint()
        ..color = const Color(0xFF2563EB)
        ..strokeWidth = 4,
    );
    canvas.drawLine(
      Offset(cx, cy),
      Offset(mirror2EndX, mirror2EndY),
      Paint()
        ..color = const Color(0xFF059669)
        ..strokeWidth = 4,
    );

    canvas.drawLine(
      Offset(cx - 10, cy - 10),
      Offset(cx + 10, cy + 10),
      Paint()
        ..color = const Color(0xFF334155)
        ..strokeWidth = 2,
    );
    canvas.drawLine(
      Offset(cx + 10, cy - 10),
      Offset(cx - 10, cy + 10),
      Paint()
        ..color = const Color(0xFF334155)
        ..strokeWidth = 2,
    );

    final arcPaint = Paint()
      ..color = const Color(0xFF7C3AED)
      ..strokeWidth = 2
      ..style = PaintingStyle.stroke;

    canvas.drawArc(
      Rect.fromCenter(center: Offset(cx, cy), width: 60, height: 60),
      -math.pi / 2 - halfAngle,
      mirrorAngleRad,
      false,
      arcPaint,
    );

    final textPainter = TextPainter(
      text: TextSpan(
        text: 'θ = ${mirrorAngleDegrees.toStringAsFixed(0)}°',
        style: const TextStyle(
          color: Color(0xFF7C3AED),
          fontSize: 14,
          fontWeight: FontWeight.bold,
