      textDirection: TextDirection.ltr,
    )..layout();
    thetaIPainter.paint(
      canvas,
      Offset(cx - arcRadius - 55, cy - arcRadius - 15),
    );

    final arcPaint2 = Paint()
      ..color = const Color(0xFFDC2626)
      ..strokeWidth = 2
      ..style = PaintingStyle.stroke;

    canvas.drawArc(
      Rect.fromCircle(center: Offset(cx, cy), radius: arcRadius),
      -math.pi / 2,
      incidentRad,
      false,
      arcPaint2,
