      Offset(
        cx + (arcRadius - 8) * math.sin(incidentStartAngle),
        cy + (arcRadius - 8) * math.cos(incidentStartAngle),
      ),
      arcPaint,
    );
    canvas.drawLine(
      Offset(
        cx + arcRadius * math.sin(-math.pi / 2),
        cy + arcRadius * math.cos(-math.pi / 2),
